     4→/**
     5→ * useNavState — drop-in replacement for useState that persists its value
     6→ * in NavStateCache under `key`.
     7→ *
     8→ * When the component remounts after tab navigation the cached value is
     9→ * restored, so the user sees the same search term / filter they left.
    10→ *
    11→ * Usage:
    12→ *   const [search, setSearch] = useNavState('inventory_search', '');
    13→ *   const [filter, setFilter] = useNavState('ledger_filter', 'all');
    14→ */
    15→export function useNavState<T>(
    16→  key: string,
    17→  initialValue: T,
    18→): [T, (value: T | ((prev: T) => T)) => void] {
    19→  const [state, setRaw] = useState<T>(() =>
    20→    NavStateCache.get<T>(key, initialValue),
    21→  );
    22→
    23→  const set = useCallback(
    24→    (value: T | ((prev: T) => T)) => {
    25→      setRaw(prev => {
    26→        const next =
    27→          typeof value === 'function'
    28→            ? (value as (prev: T) => T)(prev)
    29→            : value;
    30→        NavStateCache.save(key, next);
    31→        return next;
    32→      });
    33→    },
    34→    [key],
    35→  );
    36→
    37→  return [state, set];
    38→}
    39→
    40→/**
    41→ * useScrollRestore — attaches to any scrollable container via a ref,
    42→ * saves the scroll offset on every scroll event, and restores it on mount.
    43→ *
    44→ * Works with any element that has a `scrollTop` property.
    45→ * For Virtuoso components use their own `initialTopMostItemIndex` prop instead.
    46→ *
    47→ * Usage:
    48→ *   const listRef = useRef<HTMLDivElement>(null);
    49→ *   useScrollRestore('transactions_scroll', listRef);
    50→ *   return <div ref={listRef} className="overflow-y-auto flex-1"> ... </div>
    51→ */
    52→export function useScrollRestore(
    53→  key: string,
    54→  ref: React.RefObject<HTMLElement | null>,
    55→): void {
    56→  const restored = useRef(false);
    57→
    58→  useEffect(() => {
    59→    const el = ref.current;
    60→    if (!el) return;
    61→
    62→    if (!restored.current) {
    63→      restored.current = true;
    64→      const saved = NavStateCache.getScroll(key);
    65→      if (saved > 0) {
    66→        // rAF ensures content has rendered before we scroll
    67→        requestAnimationFrame(() => {
    68→          if (el) el.scrollTop = saved;
    69→        });
    70→      }
    71→    }
    72→
    73→    const onScroll = () => NavStateCache.saveScroll(key, el.scrollTop);
    74→    el.addEventListener('scroll', onScroll, { passive: true });
    75→    return () => el.removeEventListener('scroll', onScroll);
    76→    // eslint-disable-next-line react-hooks/exhaustive-deps
    77→  }, [key]);
    78→}
