     4→/**
     5→ * useBackHandler — register a dismiss callback with the centralised BackStack.
     6→ *
     7→ * @param dismiss   Function called when Android back is pressed and this
     8→ *                  handler is the topmost active one.
     9→ * @param enabled   Register only while this is true (e.g. `isOpen`).
    10→ *                  Automatically unregisters when it turns false or on unmount.
    11→ * @param priority  Higher = dismissed before lower-priority handlers.
    12→ *                  0 is the default; use 100 for critical dialogs.
    13→ *
    14→ * Usage (inside a modal component):
    15→ *   useBackHandler(onClose, isOpen);
    16→ */
    17→export function useBackHandler(
    18→  dismiss: () => void,
    19→  enabled: boolean,
    20→  priority = 0,
    21→): void {
    22→  const id = useId();
    23→
    24→  useEffect(() => {
    25→    if (!enabled) {
    26→      BackStack.unregister(id);
    27→      return;
    28→    }
    29→    BackStack.register(id, dismiss, priority);
    30→    return () => BackStack.unregister(id);
    31→    // dismiss may be a new function reference each render but priority and id
    32→    // are stable — only re-register when enabled or priority changes.
    33→    // eslint-disable-next-line react-hooks/exhaustive-deps
    34→  }, [id, enabled, priority, dismiss]);
    35→}
