   286→  // into one re-render via its internal notification scheduler.
   287→  const collections = ['parties', 'inventory', 'ledger', 'transactions', 'expenses', 'waste'] as const;
   288→  collections.forEach(col =>
   289→    queryClient.invalidateQueries({ queryKey: [col, userId], exact: true }),
