   293→// MODULE 4 — Bridge between React Query's QueryCache events and the UI
   294→// toast system. When a background refetch fails on a query that ALREADY has
   295→// cached data, we surface a calm "Using last saved data" toast instead of
   296→// silently leaving the user staring at potentially stale rows. Hard failures
   297→// on first-load (no cached data) are left alone — the empty/skeleton UI in
   298→// the consuming view is a clearer signal than a toast in that case.
   299→const DataErrorToastBridge: React.FC = () => {
   300→  const { showToast } = useUI();
   301→  useEffect(() => {
   302→    let lastShownAt = 0;
   303→    const COOLDOWN_MS = 30_000; // never spam — at most once every 30s
   304→    const unsub = queryClient.getQueryCache().subscribe(event => {
   305→      // We only care about the moment a query transitions into an error state.
   306→      if (event.type !== 'updated') return;
   307→      const q = event.query;
   308→      if (q.state.status !== 'error') return;
   309→      // Has cached data we can fall back on?
   310→      const hasCachedData = Array.isArray(q.state.data)
   311→        ? q.state.data.length > 0
   312→        : q.state.data != null;
   313→      if (!hasCachedData) return;
   314→      const now = Date.now();
   315→      if (now - lastShownAt < COOLDOWN_MS) return;
   316→      lastShownAt = now;
   317→      showToast('Using last saved data — check your connection', 'info');
   318→    });
   319→    return () => unsub();
   320→  }, [showToast]);
   321→  return null;
   322→};
